function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The total number of steps in any path is (m-1) + (n-1) = m + n - 2.
    // The path length (number of cells) is m + n - 1.
    const pathLength = m + n - 1;

    // dp[k][i] will store a Set of all possible XOR sums achievable when reaching
    // a cell (r, c) such that r + c = k, where r+c is the sum of coordinates.
    // Since r+c = k, the row r must be between max(0, k - (n-1)) and min(m-1, k).
    // The number of distinct sums k is from 0 to m + n - 2.
    // The number of sets stored will be m + n - 1.

    // dp[k] stores the set of XOR sums for all cells (r, c) where r + c = k.
    const dp = new Array(m + n - 1);
    for (let k = 0; k < m + n - 1; k++) {
        dp[k] = new Set();
    }

    // Base case: Start at (0, 0)
    dp[0].add(grid[0][0]);

    // Iterate over the sum of coordinates k = r + c, from 1 up to m + n - 2
    for (let k = 1; k < m + n - 1; k++) {
        // Iterate over possible rows r for this sum k
        // r must be >= 0 and r <= m - 1
        // c = k - r must be >= 0 (so r <= k) and c <= n - 1 (so k - r <= n - 1 => r >= k - n + 1)
        const startRow = Math.max(0, k - (n - 1));
        const endRow = Math.min(m - 1, k);

        for (let r = startRow; r <= endRow; r++) {
            const c = k - r;
            const currentValue = grid[r][c];

            // A cell (r, c) with sum k can be reached from:
            // 1. (r - 1, c) if r > 0. This cell has sum (r - 1) + c = k - 1.
            // 2. (r, c - 1) if c > 0. This cell has sum r + (c - 1) = k - 1.

            const prevK = k - 1;

            // Case 1: From above (r-1, c)
            if (r > 0) {
                const prevR = r - 1;
                const prevC = c;
                // Check if (prevR, prevC) is a valid cell that contributed to dp[prevK]
                // Since we iterate over all valid cells for dp[prevK], we just need to check if it's a reachable state
                // A simpler approach is to iterate over all XOR sums in dp[prevK] and see if they correspond to a cell from which (r, c) is reachable.

                // Since dp[prevK] stores XOR sums for all cells (r', c') such that r' + c' = prevK,
                // we need to find which of those cells are neighbors of (r, c).

                // Neighbors of (r, c) are (r-1, c) and (r, c-1).

                // If we came from (r-1, c):
                if (r - 1 >= 0 && c >= 0 && r - 1 + c === prevK) {
                     // The XOR sum ending at (r-1, c) must be in dp[prevK]
                     // We need a way to map XOR sums back to specific cells, which Sets don't allow easily.
                     // Let's rethink the DP state to be dp[r][c] = Set of XOR sums to reach (r, c).
                }
            }

            // Reverting to the standard 2D DP approach given the constraint M*N <= 1000.
        }
    }

    // --- Revised DP Approach: dp[r][c] = Set of all possible XOR sums to reach (r, c) ---

    const dp2 = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

    // Base Case
    dp2[0][0].add(grid[0][0]);

    // Fill first row (only right moves possible)
    for (let c = 1; c < n; c++) {
        const currentValue = grid[0][c];
        // Can only come from (0, c-1)
        for (const xorSum of dp2[0][c - 1]) {
            dp2[0][c].add(xorSum ^ currentValue);
        }
    }

    // Fill first column (only down moves possible)
    for (let r = 1; r < m; r++) {
        const currentValue = grid[r][0];
        // Can only come from (r-1, 0)
        for (const xorSum of dp2[r - 1][0]) {
            dp2[r][0].add(xorSum ^ currentValue);
        }
    }

    // Fill the rest of the grid
    for (let r = 1; r < m; r++) {
        for (let c = 1; c < n; c++) {
            const currentValue = grid[r][c];

            // From above (r-1, c)
            for (const xorSum of dp2[r - 1][c]) {
                dp2[r][c].add(xorSum ^ currentValue);
            }

            // From left (r, c-1)
            for (const xorSum of dp2[r][c - 1]) {
                dp2[r][c].add(xorSum ^ currentValue);
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    const finalXorSums = dp2[m - 1][n - 1];

    if (finalXorSums.size === 0) {
        // This should not happen given the constraints (m, n >= 1)
        return 0; 
    }

    let minXor = 1024; // Since grid[i][j] <= 1023

    for (const xorSum of finalXorSums) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

