        int currentValue = grid[r][0];
        // Can only come from (r-1, 0)
        for (int xorSum : dp[r - 1][0]) {
            dp[r][0].insert(xorSum ^ currentValue);
        }
    }

    // Fill the rest of the grid
    for (int r = 1; r < m; ++r) {
        for (int c = 1; c < n; ++c) {
            int currentValue = grid[r][c];

            // From above (r-1, c)
            for (int xorSum : dp[r - 1][c]) {
                dp[r][c].insert(xorSum ^ currentValue);
            }

            // From left (r, c-1)
            for (int xorSum : dp[r][c - 1]) {
                dp[r][c].insert(xorSum ^ currentValue);
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    const set<int>& finalXorSums = dp[m - 1][n - 1];

    if (finalXorSums.empty()) {
        // Should not happen based on constraints
        return 0; 
    }

    // Since std::set stores elements in sorted order, the smallest element is the first one.
    return finalXorSums.begin()->second;
}

